```python
import csv
import statistics
import sys
import os

def read_csv_and_compute_stats(file_path):
    if not os.path.isfile(file_path):
        print(f'错误：文件 {file_path} 不存在。')
        return None
    try:
        with open(file_path, 'r', encoding='utf-8-sig') as f:
            reader = csv.DictReader(f)
            if reader.fieldnames is None:
                print('错误：CSV 文件为空。')
                return None
            columns = {name: [] for name in reader.fieldnames}
            for row in reader:
                for col_name in reader.fieldnames:
                    columns[col_name].append(row[col_name].strip())
    except Exception as e:
        print(f'读取文件出错: {e}')
        return None
    results = {}
    for col_name, values in columns.items():
        numeric_values = []
        for v in values:
            try:
                numeric_values.append(float(v))
            except:
                pass
        if not numeric_values:
            print(f'列 {col_name}: 无数值数据，跳过。')
            continue
        mean_val = statistics.mean(numeric_values)
        stdev_val = statistics.stdev(numeric_values) if len(numeric_values) > 1 else 0.0
        results[col_name] = (mean_val, stdev_val)
    return results

def main():
    file_path = sys.argv[1] if len(sys.argv) > 1 else input('请输入 CSV 文件路径: ').strip()
    if not file_path:
        print('未提供文件路径。')
        return
    print(f'\n正在处理: {file_path}')
    print('=' * 60)
    stats = read_csv_and_compute_stats(file_path)
    if not stats:
        print('未找到数值列。' if stats is not None else '')
        return
    print(f'{"列名":<30} {"平均值":>12} {"标准差":>12}')
    print('-' * 60)
    for col_name, (mean_val, stdev_val) in stats.items():
        print(f'{col_name:<30} {mean_val:>12.4f} {stdev_val:>12.4f}')

if __name__ == '__main__':
    main()
```

保存为 csv_stats.py 后运行：python csv_stats.py 你的文件.csv。脚本自动识别数值列，计算平均值和样本标准差，仅使用 Python 标准库。
